class Solution:
    def flipBit(self, n: int, target_count: int) -> bool:
        mask = 1 << target_count
        while mask > 0:
            if (n & mask) > 0:
                return n ^ mask == n
            mask = mask >> 1
        return True

solutions.cpp:
class Solution {
public:
bool flipBit(int n, int target_count) {
	int mask = 1 << target_count;
	while (mask > 0) {
		if ((n & mask) > 0) {
			return (n ^ mask) == n;
		}
		mask = mask >> 1;
	}
	return true;
}
};
